.video-meta { color: #666; font-size: 10px; margin-bottom: 3px; }
.video-meta .channel { color: #888; }

.cat-tag {
  display: inline-block; font-size: 10px;
  padding: 1px 6px; border-radius: 10px;
  border: 1px solid #2a2a2a; color: #777;
  background: #1a1a1a; margin-bottom: 3px;
}

.stat-row {
  display: flex; gap: 6px; font-size: 10px;
  color: #666; margin-bottom: 4px; flex-wrap: wrap;
}

/* ── Efficiency Badge ── */
.eff-badge {
  display: inline-flex; align-items: center; gap: 2px;
  padding: 1px 6px; border-radius: 3px;
  font-size: 11px; font-weight: 700;
}
.eff-ultra { background: #3d0000; color: #ff4444; border: 1px solid #ff3333; }
.eff-high  { background: #2d1800; color: #ff9933; border: 1px solid #ff8800; }
.eff-mid   { background: #2a2200; color: #ffcc00; border: 1px solid #ccaa00; }
.eff-low   { background: #1e1e1e; color: #555;    border: 1px solid #2a2a2a; }

/* ── AI Button ── */
.btn-ai {
  background: #1a1a2e; border: 1px solid #3a3a88;
  color: #8888ee; padding: 1px 7px;
  border-radius: 3px; cursor: pointer; font-size: 10px;
  margin-left: 3px;
}
.btn-ai:hover { background: #22224a; color: #aaaaff; }

/* ── 더보기 ── */
.load-more-wrap { padding: 10px 10px; display: none; }
.btn-more {
  width: 100%;
  background: #1e1e1e; border: 1px solid #333;
  color: #aaa; padding: 6px;
  border-radius: 4px; cursor: pointer; font-size: 11px;
}
.btn-more:hover { background: #2a2a2a; }

/* ── Loading / Empty ── */
.loading-box {
  text-align: center; padding: 60px 20px; color: #666;
  grid-column: 1 / -1;
}

