function makeKeywordAddBtn() {
  const wrap = document.createElement('div');
  wrap.className = 'exclude-add';
  wrap.style.borderColor = '#8b4444';
  wrap.style.color = '#bb8888';
  wrap.innerHTML = `
    <span>+ 키워드 제외</span>
    <div class="exclude-dropdown" id="kwDropdown">
      <div style="padding:6px 8px;display:flex;gap:4px;">
        <input id="kwInput" type="text" placeholder="키워드 입력 후 Enter"
          style="flex:1;background:#111;border:1px solid #444;color:#ddd;
                 padding:3px 7px;border-radius:3px;font-size:11px;min-width:130px;"
          onclick="event.stopPropagation()">
        <button onclick="addKeyword()" style="background:#333;border:1px solid #555;
          color:#ccc;padding:3px 8px;border-radius:3px;cursor:pointer;font-size:11px;">추가</button>
      </div>
    </div>
  `;

  wrap.addEventListener('click', (e) => {
    if (e.target.closest('#kwInput') || e.target.closest('button[onclick="addKeyword()"]')) return;
    const dd = wrap.querySelector('.exclude-dropdown');
    const isOpen = dd.classList.toggle('open');
    if (isOpen) {
      setTimeout(() => { wrap.querySelector('#kwInput')?.focus(); }, 50);
      setTimeout(() => {
        document.addEventListener('click', function closer(ev) {
          if (!wrap.contains(ev.target)) {
            dd.classList.remove('open');
            document.removeEventListener('click', closer);
          }
        });
      }, 0);
    }
    e.stopPropagation();
  });

  // Enter 키
  wrap.querySelector('#kwInput')?.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') { e.stopPropagation(); addKeyword(); }
  });

  return wrap;
}

