  /이혼|열애|결혼 발표|임신|출산|열애설|교제/,
  /시상식|드라마 방영|영화 개봉|시즌/,
];

function classifyTrend(title) {
  if (TREND_PATTERNS_SKIP.some(p => p.test(title))) return 'skip';
  if (TREND_PATTERNS_INFO.some(p => p.test(title))) return 'info';
  return 'neutral';
}

