   496→<script>
   497→// ── 카테고리 맵 ──────────────────────────────────
   498→const CAT = {
   499→  '1':'영화/애니','2':'자동차','10':'음악','15':'반려동물',
   500→  '17':'스포츠','19':'여행','20':'게임','22':'블로그',
   501→  '23':'코미디','24':'엔터테인먼트','25':'뉴스/정치',
   502→  '26':'스타일','27':'교육','28':'과학/기술','29':'비영리'
   503→};
   504→
   505→// ── 필터 상태 (제거 가능) ────────────────────────
   506→const filters = {
   507→  excludedCats: new Set(['1', '10', '17', '20', '24']), // 영화/애니, 음악, 스포츠, 게임, 엔터테인먼트
   508→  excludedKeywords: ['플레이리스트', 'playlist', '노래모음', '음악모음', '음악 모음', 'BGM', 'bgm', 'lofi', 'lo-fi', 'M/V', ' MV '],
   509→  minSubs:     1000,
   510→  minViews:    50000,
   511→  minComments: 100,
   512→};
   513→
   514→// ── Trend Keyword Classifier ─────────────────────
   515→const TREND_PATTERNS_INFO = [
   516→  /개화|시기|날씨|기온|예보|기상/,
   517→  /주가|금리|환율|부동산|경제|정책|법안|규제|예산|물가|세금/,
   518→  /AI|인공지능|기술|연구|발견|개발|특허|로봇|반도체/,
   519→  /역사|독립|영토|사건|재판|판결|수사|검찰|사고|범죄|수사/,
   520→  /건강|질병|치료|의학|백신|의료|바이러스|암|수술/,
   521→  /교육|시험|입시|수능|학교|대학|장학/,
   522→  /독도|영토|외교|정상회담|조약|협약|제재/,
   523→  /채용|취업|일자리|실업|임금|최저임금/,
   524→  /환경|기후|탄소|에너지|태양광|원전/,
   525→];
   526→const TREND_PATTERNS_SKIP = [
   527→  /march madness|NBA|NFL|EPL|리그|결승|토너먼트|올림픽|월드컵|챔피언십/i,
   528→  /공연|콘서트|컴백|앨범|데뷔|팬미팅|뮤직비디오|음반/,
   529→  /이혼|열애|결혼 발표|임신|출산|열애설|교제/,
   530→  /시상식|드라마 방영|영화 개봉|시즌/,
   531→];
   532→
   533→function classifyTrend(title) {
   534→  if (TREND_PATTERNS_SKIP.some(p => p.test(title))) return 'skip';
   535→  if (TREND_PATTERNS_INFO.some(p => p.test(title))) return 'info';
   536→  return 'neutral';
   537→}
   538→
   539→// ── Google Trends ────────────────────────────────
   540→const TRENDS_WORKER = 'https://google-trend.coreawin-ffa.workers.dev/';
   541→const TRENDS_CACHE_KEY = 'yt_trends_cache';
   542→
   543→// 현재 캐시 슬롯 (매시 정각·30분 기준 타임스탬프)
   544→function getCacheSlot() {
   545→  const now = new Date();
   546→  const slot = new Date(now);
   547→  slot.setMinutes(now.getMinutes() < 30 ? 0 : 30, 0, 0);
   548→  return slot.getTime();
   549→}
   550→
   551→async function loadTrends(forceRefresh = false) {
   552→  const listEl = document.getElementById('trendsList');
   553→  const metaEl = document.getElementById('trendsMeta');
   554→
   555→  // 캐시 확인
   556→  if (!forceRefresh) {
   557→    try {
   558→      const cached = JSON.parse(localStorage.getItem(TRENDS_CACHE_KEY) || 'null');
   559→      if (cached && cached.slot === getCacheSlot()) {
   560→        renderTrends(cached.data, cached.fetchedAt);
   561→        return;
   562→      }
   563→    } catch (_) {}
   564→  }
   565→
   566→  listEl.innerHTML = '<span class="trends-loading">트렌드 로딩 중...</span>';
   567→  metaEl.textContent = '';
   568→
   569→  try {
   570→    const res  = await fetch(TRENDS_WORKER);
   571→    const text = await res.text();
   572→
   573→    // RSS XML 파싱
   574→    const parser = new DOMParser();
   575→    const xml    = parser.parseFromString(text, 'text/xml');
   576→    const items  = [...xml.querySelectorAll('item')];
   577→
   578→    const trends = items.map(item => ({
   579→      title:   item.querySelector('title')?.textContent?.trim() || '',
   580→      traffic: item.querySelector('ht\\:approx_traffic')?.textContent?.trim() || '',
   581→    })).filter(t => t.title);
   582→
   583→    // 캐시 저장
   584→    const cache = { slot: getCacheSlot(), data: trends, fetchedAt: Date.now() };
   585→    localStorage.setItem(TRENDS_CACHE_KEY, JSON.stringify(cache));
   586→
   587→    renderTrends(trends, cache.fetchedAt);
   588→
   589→  } catch (e) {
   590→    listEl.innerHTML = '<span class="trends-loading" style="color:#555;">트렌드 로딩 실패</span>';
   591→  }
   592→}
   593→
   594→function renderTrends(trends, fetchedAt) {
   595→  const listEl = document.getElementById('trendsList');
   596→  const metaEl = document.getElementById('trendsMeta');
   597→
   598→  if (!trends || trends.length === 0) {
   599→    listEl.innerHTML = '<span class="trends-loading" style="color:#555;">데이터 없음</span>';
   600→    return;
   601→  }
   602→
   603→  listEl.innerHTML = '';
   604→
   605→  // 정보성 → 중립 → 스킵 순으로 정렬
   606→  const sorted = [...trends].sort((a, b) => {
   607→    const order = { info: 0, neutral: 1, skip: 2 };
   608→    return order[classifyTrend(a.title)] - order[classifyTrend(b.title)];
   609→  });
   610→
   611→  sorted.forEach(t => {
   612→    const type = classifyTrend(t.title);
   613→    const chip = document.createElement('button');
   614→    chip.className = `trend-chip ${type}`;
   615→
   616→    const tagLabel = type === 'info' ? '✅정보' : type === 'skip' ? '🔘' : '';
   617→    const tagHtml  = tagLabel ? `<span class="trend-tag ${type}">${tagLabel}</span>` : '';
   618→
   619→    chip.innerHTML = `${esc(t.title)}${tagHtml}${t.traffic ? `<span class="traffic">${esc(t.traffic)}</span>` : ''}`;
   620→    chip.title = type === 'info' ? '정보성 키워드' : type === 'skip' ? '연예/스포츠 키워드' : '';
   621→    chip.addEventListener('click', () => {
   622→      document.getElementById('searchQuery').value = t.title;
   623→      doSearch();
   624→    });
   625→    listEl.appendChild(chip);
   626→  });
   627→
   628→  // 캐시 시각 표시
   629→  const d = new Date(fetchedAt);
   630→  const timeStr = `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
   631→  const slotStr = d.getMinutes() < 30 ? `${String(d.getHours()).padStart(2,'0')}:00` : `${String(d.getHours()).padStart(2,'0')}:30`;
   632→  metaEl.textContent = `${slotStr} 기준`;
   633→}
   634→
   635→// ── State ────────────────────────────────────────
   636→let state = { period: 'week', advOpen: false, allVideos: [], sec1Shown: 15 };
   637→
   638→// ── Init ─────────────────────────────────────────
   639→window.addEventListener('DOMContentLoaded', () => {
   640→  const saved = localStorage.getItem('yt_api_key');
   641→  if (saved) {
   642→    document.getElementById('apiKey').value = saved;
   643→    document.getElementById('apiStatus').textContent = '✓ 저장됨';
   644→  }
   645→  loadTrends(); // Google Trends 로딩 (캐시 우선)
   646→  renderChips();
   647→  if (getKey()) doSearch();
   648→  else {
   649→    document.getElementById('threeCol').innerHTML =
   650→      '<div class="loading-box" style="color:#555;">상단에 API 키를 입력 후 검색하세요.</div>';
   651→  }
   652→});
   653→
   654→// ── API Key ──────────────────────────────────────
   655→function saveApiKey() {
   656→  const key = document.getElementById('apiKey').value.trim();
   657→  if (!key) return;
   658→  localStorage.setItem('yt_api_key', key);
   659→  document.getElementById('apiStatus').textContent = '✓ 저장됨';
   660→  setTimeout(() => { document.getElementById('apiStatus').textContent = ''; }, 2000);
   661→  doSearch();
   662→}
   663→function getKey() { return document.getElementById('apiKey').value.trim(); }
   664→
   665→// ── Period ───────────────────────────────────────
   666→function setPeriod(btn) {
   667→  document.querySelectorAll('.period-btn').forEach(b => b.classList.remove('active'));
   668→  btn.classList.add('active');
   669→  state.period = btn.dataset.p;
   670→  doSearch();
   671→}
   672→function getPeriodISO(p) {
   673→  const d = new Date();
   674→  switch (p) {
   675→    case 'today':   d.setHours(0,0,0,0); return d.toISOString();
   676→    case 'week':    d.setDate(d.getDate()-7); return d.toISOString();
   677→    case 'month':   d.setMonth(d.getMonth()-1); return d.toISOString();
   678→    case '3months': d.setMonth(d.getMonth()-3); return d.toISOString();
   679→    default: return null;
   680→  }
   681→}
   682→function getPeriodLabel(p) {
   683→  return { today:'오늘', week:'1주일', month:'1개월', '3months':'3개월', all:'전체' }[p] || p;
   684→}
   685→
   686→// ── Advanced ─────────────────────────────────────
   687→function toggleAdv() {
   688→  state.advOpen = !state.advOpen;
   689→  document.getElementById('filterAdv').classList.toggle('open', state.advOpen);
   690→  document.getElementById('advToggle').textContent = (state.advOpen ? '▲' : '▼') + ' 고급필터';
   691→}
   692→
   693→// ── Active Filter Chips ───────────────────────────
   694→function renderChips() {
   695→  const wrap = document.getElementById('activeFilters');
   696→  wrap.innerHTML = '';
   697→
   698→  // 기간
   699→  if (state.period !== 'all') {
   700→    wrap.appendChild(makeChip(`기간: ${getPeriodLabel(state.period)}`, 'gray', () => {
   701→      document.querySelector('[data-p="all"]').click();
   702→    }));
   703→  }
   704→
   705→  // 영상 길이
   706→  const dur = document.getElementById('fDuration').value;
   707→  const durLabel = { short:'4분↓', medium:'4~20분', long:'20분↑' };
   708→  if (dur !== 'any') {
   709→    wrap.appendChild(makeChip(`길이: ${durLabel[dur]}`, 'gray', () => {
   710→      document.getElementById('fDuration').value = 'any';
   711→      doSearch();
   712→    }));
   713→  }
   714→
   715→  // 제외 카테고리 칩
   716→  filters.excludedCats.forEach(id => {
   717→    wrap.appendChild(makeChip(`${CAT[id]||id} 제외`, 'red', () => {
   718→      filters.excludedCats.delete(id);
   719→      doSearch();
   720→    }));
   721→  });
   722→
   723→  // 제외 추가 버튼
   724→  wrap.appendChild(makeExcludeAddBtn());
   725→
   726→  // 제외 키워드 칩
   727→  filters.excludedKeywords.forEach((kw, idx) => {
   728→    wrap.appendChild(makeChip(`"${kw}" 제외`, 'red', () => {
   729→      filters.excludedKeywords.splice(idx, 1);
   730→      doSearch();
   731→    }));
   732→  });
   733→
   734→  // 키워드 제외 추가 버튼
   735→  wrap.appendChild(makeKeywordAddBtn());
   736→
   737→  // 품질 필터
   738→  if (filters.minSubs > 0) {
   739→    wrap.appendChild(makeChip(`구독자 ${fmt(filters.minSubs)}↑`, 'blue', () => {
   740→      filters.minSubs = 0; doSearch();
   741→    }));
   742→  }
   743→  if (filters.minViews > 0) {
   744→    wrap.appendChild(makeChip(`조회수 ${fmt(filters.minViews)}↑`, 'blue', () => {
   745→      filters.minViews = 0; doSearch();
   746→    }));
   747→  }
   748→  if (filters.minComments > 0) {
   749→    wrap.appendChild(makeChip(`댓글 ${filters.minComments}↑`, 'blue', () => {
   750→      filters.minComments = 0; doSearch();
   751→    }));
   752→  }
   753→}
   754→
   755→function makeExcludeAddBtn() {
   756→  // 제외 가능한 카테고리 목록 (현재 미제외 항목만)
   757→  const available = Object.entries(CAT).filter(([id]) => !filters.excludedCats.has(id));
   758→
   759→  const wrap = document.createElement('div');
   760→  wrap.className = 'exclude-add';
   761→  wrap.innerHTML = `
   762→    <span>+ 카테고리 제외</span>
