   893→// ── Core Search ───────────────────────────────────
   894→async function runSearch() {
   895→  try {
   896→    const key    = getKey();
   897→    const region = document.getElementById('fRegion').value;
   898→    const catId  = document.getElementById('fCategory').value;
   899→    const query  = document.getElementById('searchQuery').value.trim();
   900→
   901→    let videos = [], mode = '';
   902→
   903→    if (!query) {
   904→      // ── 검색어 없음: 다중 카테고리 병렬 검색 ──
   905→      mode = '종합 카테고리';
   906→      const TARGET_CATS = ['22', '23', '25', '26', '27', '28']; // 블로그,코미디,뉴스,노하우,교육,과학
   907→      const after = getPeriodISO(state.period);
   908→      const dur   = document.getElementById('fDuration').value;
   909→
   910→      // 카테고리별 병렬 search.list
   911→      const searchResults = await Promise.all(
   912→        TARGET_CATS.map(cId => {
   913→          const p = new URLSearchParams({
   914→            part: 'snippet', type: 'video', maxResults: 50,
   915→            order: 'viewCount', regionCode: region,
   916→            videoDuration: dur, key,
   917→          });
   918→          p.set('videoCategoryId', cId);
   919→          if (after) p.set('publishedAfter', after);
   920→          return fetchJson('https://www.googleapis.com/youtube/v3/search?' + p);
   921→        })
   922→      );
   923→
   924→      // 합치기 + 중복 제거
   925→      const seenIds = new Set();
   926→      const allItems = [];
   927→      searchResults.forEach(data => {
   928→        if (data.error) return;
   929→        (data.items||[]).filter(i => i.id?.videoId).forEach(item => {
   930→          if (!seenIds.has(item.id.videoId)) {
   931→            seenIds.add(item.id.videoId);
   932→            allItems.push(item);
   933→          }
   934→        });
   935→      });
   936→
   937→      if (allItems.length === 0) { renderEmpty(); updateInfo(mode, 0); return; }
   938→
   939→      // videoId / channelId 배치 분할 (50개씩)
   940→      const videoIds   = allItems.map(i => i.id.videoId);
   941→      const channelIds = [...new Set(allItems.map(i => i.snippet.channelId))];
   942→      const chunk = (arr, n) => Array.from({ length: Math.ceil(arr.length/n) }, (_, i) => arr.slice(i*n, i*n+n));
   943→
   944→      const [videoResults, channelResults] = await Promise.all([
   945→        Promise.all(chunk(videoIds, 50).map(ids =>
   946→          fetchJson(`https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet&id=${ids.join(',')}&key=${key}`)
   947→        )),
   948→        Promise.all(chunk(channelIds, 50).map(ids =>
   949→          fetchJson(`https://www.googleapis.com/youtube/v3/channels?part=statistics&id=${ids.join(',')}&key=${key}`)
   950→        )),
   951→      ]);
   952→
   953→      const vMap  = {};
   954→      videoResults.forEach(d => (d.items||[]).forEach(v => { vMap[v.id] = v; }));
   955→      const chMap = {};
   956→      channelResults.forEach(d => (d.items||[]).forEach(c => { chMap[c.id] = c; }));
   957→
   958→      videos = allItems.reduce((acc, item) => {
   959→        const v = vMap[item.id.videoId];
   960→        if (v) acc.push(makeVideoObj(v.id, v.snippet || item.snippet, v.statistics, chMap));
   961→        return acc;
   962→      }, []);
   963→
   964→    } else {
   965→      // ── 검색어 있음 ──
   966→      mode = `"${query}" 검색`;
   967→      const sp = new URLSearchParams({
   968→        part: 'snippet', type: 'video', maxResults: 50,
   969→        order: document.getElementById('fOrder').value,
   970→        regionCode: region,
   971→        videoDuration: document.getElementById('fDuration').value,
   972→        videoDefinition: document.getElementById('fDefinition').value,
   973→        safeSearch: document.getElementById('fSafe').value,
   974→        q: query, key,
   975→      });
   976→      if (catId) sp.set('videoCategoryId', catId);
   977→      const lang = document.getElementById('fLang').value;
   978→      if (lang) sp.set('relevanceLanguage', lang);
   979→      const after = getPeriodISO(state.period);
