   985→      const items = (sd.items||[]).filter(i => i.id?.videoId);
   986→      if (items.length === 0) { renderEmpty(); updateInfo(mode, 0); return; }
   987→
   988→      const vIds  = items.map(i => i.id.videoId).join(',');
   989→      const chIds = [...new Set(items.map(i => i.snippet.channelId))].join(',');
   990→
   991→      const [vData, chData] = await Promise.all([
   992→        fetchJson(`https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet&id=${vIds}&key=${key}`),
   993→        fetchJson(`https://www.googleapis.com/youtube/v3/channels?part=statistics&id=${chIds}&key=${key}`),
   994→      ]);
   995→      if (vData.error)  throw new Error(vData.error.message);
   996→      if (chData.error) throw new Error(chData.error.message);
   997→
   998→      const vMap  = Object.fromEntries((vData.items||[]).map(v => [v.id, v]));
   999→      const chMap = Object.fromEntries((chData.items||[]).map(c => [c.id, c]));
  1000→
  1001→      videos = items.reduce((acc, item) => {
  1002→        const v = vMap[item.id.videoId];
  1003→        if (v) acc.push(makeVideoObj(v.id, v.snippet || item.snippet, v.statistics, chMap));
  1004→        return acc;
  1005→      }, []);
  1006→    }
  1007→
  1008→    // 품질 필터 → 효율성 정렬
  1009→    videos = videos.filter(passQuality);
  1010→    videos.sort((a, b) => b.eff - a.eff);
  1011→    state.allVideos = videos;
  1012→
  1013→    updateInfo(mode, videos.length);
  1014→    renderThreeCols();
  1015→
  1016→  } catch (err) {
  1017→    document.getElementById('threeCol').innerHTML = '<div class="loading-box"></div>';
  1018→    showError('오류: ' + err.message);
  1019→  }
  1020→}
