  1022→function makeVideoObj(id, snippet, statistics, chMap) {
  1023→  const s    = statistics || {};
  1024→  const ch   = chMap[snippet.channelId] || {};
  1025→  const subs = parseInt(ch.statistics?.subscriberCount || 0);
  1026→  const catId = snippet.categoryId || '';
  1027→  return {
  1028→    videoId: id,
  1029→    title: snippet.title,
  1030→    channelTitle: snippet.channelTitle,
  1031→    publishedAt: snippet.publishedAt,
  1032→    thumbnail: snippet.thumbnails?.medium?.url || snippet.thumbnails?.default?.url || '',
  1033→    catId, catName: CAT[catId] || '',
  1034→    views:    parseInt(s.viewCount    || 0),
  1035→    likes:    parseInt(s.likeCount    || 0),
  1036→    comments: parseInt(s.commentCount || 0),
  1037→    subs,
  1038→    eff: subs > 0 ? parseInt(s.viewCount || 0) / subs : 0,
  1039→  };
  1040→}
