  1042→// ── Render 3열 ────────────────────────────────────
  1043→function renderThreeCols() {
  1044→  const all = state.allVideos;
  1045→
  1046→  const catCount = {};
  1047→  all.forEach(v => { if (v.catId) catCount[v.catId] = (catCount[v.catId]||0) + 1; });
  1048→  const topCats = Object.entries(catCount).sort((a,b)=>b[1]-a[1]).slice(0,2).map(([id])=>id);
  1049→
  1050→  const col = document.getElementById('threeCol');
  1051→  col.innerHTML = '';
  1052→
  1053→  col.appendChild(buildCol({
  1054→    badge:'1열', badgeCat:false, title:'전체 효율성 TOP',
  1055→    subCount:`${all.length}개`, videos:all, showMore:true, colIdx:1,
  1056→  }));
  1057→
  1058→  const cat1 = topCats[0] || null;
  1059→  const cat1v = cat1 ? all.filter(v=>v.catId===cat1) : [];
  1060→  col.appendChild(buildCol({
  1061→    badge:'2열', badgeCat:true,
  1062→    title: cat1 ? (CAT[cat1]||cat1) : '—',
  1063→    subCount: cat1 ? `${cat1v.length}개` : '',
  1064→    videos: cat1v, showMore:false, colIdx:2,
  1065→  }));
  1066→
  1067→  const cat2 = topCats[1] || null;
  1068→  const cat2v = cat2 ? all.filter(v=>v.catId===cat2) : [];
  1069→  col.appendChild(buildCol({
  1070→    badge:'3열', badgeCat:true,
  1071→    title: cat2 ? (CAT[cat2]||cat2) : '—',
  1072→    subCount: cat2 ? `${cat2v.length}개` : '',
  1073→    videos: cat2v, showMore:false, colIdx:3,
  1074→  }));
  1075→}
  1076→
  1077→function buildCol({ badge, badgeCat, title, subCount, videos, showMore, colIdx }) {
  1078→  const el = document.createElement('div');
  1079→  el.className = 'col';
  1080→  const shown = showMore ? videos.slice(0, state.sec1Shown) : videos.slice(0, 20);
  1081→  const remaining = videos.length - state.sec1Shown;
  1082→
  1083→  el.innerHTML = `
  1084→    <div class="col-header">
  1085→      <div class="col-title">
  1086→        <span class="col-badge${badgeCat?' cat':''}">${esc(badge)}</span>${esc(title)}
  1087→      </div>
  1088→      <div class="col-count">${esc(subCount)}</div>
  1089→    </div>
  1090→    <div class="col-list" id="colList${colIdx}"></div>
  1091→    ${showMore && remaining > 0 ? `
  1092→      <div class="load-more-wrap" style="display:block;">
  1093→        <button class="btn-more" onclick="showMore()">더 보기 (${remaining}개 남음)</button>
  1094→      </div>` : ''}
  1095→  `;
  1096→
  1097→  const list = el.querySelector(`#colList${colIdx}`);
  1098→  if (shown.length === 0) {
  1099→    list.innerHTML = '<div class="empty-box">해당 카테고리 영상 없음</div>';
  1100→  } else {
  1101→    shown.forEach(v => list.appendChild(buildCard(v)));
  1102→  }
  1103→  return el;
  1104→}
  1105→
  1106→function showMore() {
  1107→  state.sec1Shown = Math.min(state.sec1Shown + 10, state.allVideos.length);
  1108→  renderThreeCols();
  1109→}
  1110→
  1111→// ── Card ─────────────────────────────────────────
  1112→function buildCard(v) {
  1113→  const d = new Date(v.publishedAt);
  1114→  const dateStr = `${d.getFullYear()}.${pad(d.getMonth()+1)}.${pad(d.getDate())}`;
  1115→  const effStr = v.eff > 0 ? v.eff.toFixed(1)+'배' : '—';
  1116→  let effClass='eff-low', effIcon='', effTag='효율';
  1117→  if      (v.eff>=50){ effClass='eff-ultra'; effIcon='🔥'; effTag='초급상승'; }
  1118→  else if (v.eff>=10){ effClass='eff-high';  effIcon='⚡'; effTag='급상승';   }
  1119→  else if (v.eff>=3) { effClass='eff-mid';   effIcon='↑';  effTag='인기';     }
  1120→
  1121→  const el = document.createElement('div');
  1122→  el.className = 'video-card';
  1123→  el.innerHTML = `
  1124→    <div class="thumb-wrap">
  1125→      <a href="https://www.youtube.com/watch?v=${esc(v.videoId)}" target="_blank" rel="noopener">
  1126→        <img class="thumb" src="${esc(v.thumbnail)}" alt="" loading="lazy">
  1127→      </a>
  1128→    </div>
  1129→    <div class="video-info">
  1130→      <div class="video-title">
