  1132→      </div>
  1133→      <div class="video-meta"><span class="channel">${esc(v.channelTitle)}</span> · ${dateStr}</div>
  1134→      ${v.catName ? `<span class="cat-tag">${esc(v.catName)}</span>` : ''}
  1135→      <div class="stat-row">
  1136→        <span>👁 ${fmt(v.views)}</span>
  1137→        <span>👍 ${fmt(v.likes)}</span>
  1138→        <span>💬 ${fmt(v.comments)}</span>
  1139→        <span>👥 ${fmt(v.subs)}</span>
  1140→      </div>
  1141→      <div>
  1142→        <span class="eff-badge ${effClass}">${effIcon} ${effTag} ${effStr}</span>
  1143→        <button class="btn-ai" onclick='openModal(${JSON.stringify(v.title)},${JSON.stringify(v.channelTitle)})'>🤖 AI 분석</button>
  1144→      </div>
  1145→    </div>
  1146→  `;
  1147→  return el;
  1148→}
  1149→
  1150→// ── Helpers ───────────────────────────────────────
  1151→function showLoading() {
  1152→  document.getElementById('threeCol').innerHTML =
  1153→    '<div class="loading-box"><div class="spinner"></div>불러오는 중...</div>';
  1154→  document.getElementById('resultsInfo').style.display = 'none';
  1155→}
  1156→function renderEmpty() {
  1157→  document.getElementById('threeCol').innerHTML =
  1158→    '<div class="loading-box" style="color:#555;">조건에 맞는 영상이 없습니다.<br><small style="font-size:11px;color:#444;">필터 칩을 클릭하여 조건을 완화해보세요.</small></div>';
  1159→}
  1160→function updateInfo(mode, count) {
  1161→  const el = document.getElementById('resultsInfo');
  1162→  el.style.display = 'block';
  1163→  el.innerHTML = `<strong>${count}개</strong> 결과 · 효율성 기준 정렬 <span class="mode-badge">${esc(mode)}</span>`;
  1164→}
  1165→async function fetchJson(url) { return (await fetch(url)).json(); }
  1166→function fmt(n) {
  1167→  n = Number(n);
  1168→  if (n>=100_000_000) return (n/100_000_000).toFixed(1)+'억';
  1169→  if (n>=10_000)      return (n/10_000).toFixed(1)+'만';
  1170→  if (n>=1_000)       return (n/1_000).toFixed(1)+'K';
  1171→  return n.toLocaleString();
  1172→}
  1173→function pad(n) { return String(n).padStart(2,'0'); }
  1174→function esc(str) {
  1175→  return String(str)
  1176→    .replace(/&/g,'&amp;').replace(/</g,'&lt;')
  1177→    .replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
  1178→}
  1179→function showError(msg) {
