// ── Channel Panel ─────────────────────────────────
const CH_B_CACHE_KEY = 'yt_ch_b_v1';
const CH_D_CACHE_KEY = 'yt_ch_d_v1';

function getHourSlot() {
  const n = new Date();
  return new Date(n.getFullYear(), n.getMonth(), n.getDate(), n.getHours()).getTime();
}
function get6HourSlot() {
  const n = new Date();
  return new Date(n.getFullYear(), n.getMonth(), n.getDate(), Math.floor(n.getHours()/6)*6).getTime();
}

function calcAiDifficulty(topVideos) {
  const catCounts = {};
  topVideos.forEach(v => { if (v.catId) catCounts[v.catId] = (catCounts[v.catId]||0)+1; });
  const dom = Object.entries(catCounts).sort((a,b)=>b[1]-a[1])[0]?.[0] || '';
  const titles = topVideos.map(v => v.title).join(' ');
  if (['27','28','25'].includes(dom)) return { level:1, label:'🟢 쉬움' };
  if (/란\?|하는\s?법|TOP\s?\d|역사|정보|분석|이유|원인|비교|차이|설명|진실|사실/.test(titles))
    return { level:1, label:'🟢 쉬움' };
  if (['22','23','26'].includes(dom)) return { level:3, label:'🟠 주의' };
  if (/브이로그|vlog|요리|여행|먹방|일상|체험|현장|직접/.test(titles.toLowerCase()))
    return { level:3, label:'🟠 주의' };
  return { level:2, label:'🟡 보통' };
}

function renderChannelCol(el) {
  if (!el) return;

  const headerHtml = (meta) => `
    <div class="col-header">
      <div class="col-title">
        <span class="col-badge">3열</span>추천 채널
        <button class="ch-refresh-btn" onclick="refreshChannelPanel()" title="새로고침">↺</button>
      </div>
      <div class="col-count ch-last-update" id="col3Meta">${meta}</div>
    </div>`;

  if (state.channelLoading && !state.channelData) {
    el.innerHTML = headerHtml('로딩 중...') +
      `<div class="col-list"><div class="loading-box" style="padding:40px 20px;"><div class="spinner"></div>채널 로딩 중...</div></div>`;
    return;
  }
  if (!state.channelData) {
    el.innerHTML = headerHtml('') +
      `<div class="col-list"><div class="ch-no-data">↺ 버튼을 눌러 채널을 불러오세요</div></div>`;
    return;
  }

  const { channels, updatedAt } = state.channelData;
  const d = new Date(updatedAt);
  const timeStr = `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')} 기준`;

  el.innerHTML = headerHtml(timeStr) + `<div class="col-list" id="col3List"></div>`;

  const list = el.querySelector('#col3List');
  if (!channels.length) { list.innerHTML = '<div class="ch-no-data">추천 채널 없음</div>'; return; }
  channels.forEach(ch => list.appendChild(buildChannelCard(ch)));
}

function buildChannelCard(ch) {
  const el = document.createElement('div');
  el.className = 'channel-card';
  const diff = ch.aiDiff || { level:2, label:'🟡 보통' };
  const catName = ch.top3?.[0] ? (CAT[ch.top3[0].catId] || '') : '';

  el.innerHTML = `
    <div class="ch-header">
      <img class="ch-thumb" src="${esc(ch.thumbnail)}" alt="" loading="lazy">
      <div class="ch-info">
        <div class="ch-name">
          <a href="https://www.youtube.com/channel/${esc(ch.channelId)}" target="_blank" rel="noopener">${esc(ch.title)}</a>
        </div>
        <div class="ch-meta">구독자 ${fmt(ch.subs)} · 영상 ${fmt(ch.videoCount)}개</div>
        <div class="ch-tags">
          ${catName ? `<span class="ch-cat-tag">${esc(catName)}</span>` : ''}
          <span class="ai-diff-badge diff-${diff.level}">${esc(diff.label)}</span>
          <span class="ch-source-tag${ch.source==='D'?' d-src':''}">${ch.source==='B'?'인기차트':'채널검색'}</span>
        </div>
      </div>
    </div>`;

  if (!ch.hasRecentVideos || !ch.top3?.length) {
    el.innerHTML += `<div class="ch-inactive-note">최근 90일 업로드 없음</div>`;
    return el;
  }

  const vHtml = ch.top3.map((v, i) => {
    const days = Math.floor((Date.now() - new Date(v.publishedAt).getTime()) / 86400000);
    const daysStr = days === 0 ? '오늘' : days === 1 ? '어제' : `${days}일 전`;
    const recClass = days <= 7 ? 'fresh' : days <= 30 ? 'recent' : '';
    let effClass='eff-low', effIcon='';
    if      (v.baseEff>=50){ effClass='eff-ultra'; effIcon='🔥'; }
    else if (v.baseEff>=10){ effClass='eff-high';  effIcon='⚡'; }
    else if (v.baseEff>=3) { effClass='eff-mid';   effIcon='↑';  }
    const effStr = v.baseEff > 0 ? v.baseEff.toFixed(1)+'배' : '—';
    return `
      <div class="ch-video-item">
        <span class="ch-rank">${i+1}</span>
        <a href="https://www.youtube.com/watch?v=${esc(v.videoId)}" target="_blank" rel="noopener">
          <img class="ch-video-thumb" src="${esc(v.thumbnail)}" alt="" loading="lazy">
        </a>
        <div class="ch-video-info">
          <div class="ch-video-title">
            <a href="https://www.youtube.com/watch?v=${esc(v.videoId)}" target="_blank" rel="noopener">${esc(v.title)}</a>
          </div>
          <div class="ch-video-stats">
            <span class="eff-badge ${effClass}" style="font-size:10px;padding:0 5px;">${effIcon} ${effStr}</span>
            <span class="ch-recency ${recClass}">${daysStr}</span>
            <span style="font-size:10px;color:#555;">👁 ${fmt(v.views)}</span>
          </div>
        </div>
      </div>`;
  }).join('');
  el.innerHTML += `<div class="ch-videos">${vHtml}</div>`;
  return el;
}

function refreshChannelPanel() { loadChannelPanel(true); }

async function loadChannelPanel(forceRefresh = false) {
  if (state.channelLoading) return;
  const key = getKey();
  if (!key) return;

  state.channelLoading = true;
  const col3El = document.getElementById('col3Panel');
  if (col3El) renderChannelCol(col3El);

  try {
    const region = document.getElementById('fRegion').value;

    // ── B방식: mostPopular 채널 (1시간 캐시) ──
    let bChannelIds = [];
    const bSlot = getHourSlot();
    if (!forceRefresh) {
      try {
        const c = JSON.parse(localStorage.getItem(CH_B_CACHE_KEY)||'null');
        if (c && c.slot === bSlot) bChannelIds = c.data;
      } catch(_) {}
    }
    if (!bChannelIds.length) {
      const popRes = await Promise.all(
        ['25','26','27','28'].map(cId =>
          fetchJson(`https://www.googleapis.com/youtube/v3/videos?part=snippet&chart=mostPopular&videoCategoryId=${cId}&regionCode=${region}&maxResults=20&key=${key}`)
        )
      );
      const seen = new Set();
      popRes.forEach(d => {
        (d.items||[]).forEach(v => {
          const chId = v.snippet?.channelId;
          if (chId && !seen.has(chId)) { seen.add(chId); bChannelIds.push(chId); }
        });
      });
      localStorage.setItem(CH_B_CACHE_KEY, JSON.stringify({ slot: bSlot, data: bChannelIds }));
    }

    // ── D방식: 채널 검색 (6시간 캐시) ──
    let dChannelIds = [];
    const dSlot = get6HourSlot();
    if (!forceRefresh) {
      try {
        const c = JSON.parse(localStorage.getItem(CH_D_CACHE_KEY)||'null');
        if (c && c.slot === dSlot) dChannelIds = c.data;
      } catch(_) {}
    }
    if (!dChannelIds.length) {
      const dRes = await Promise.all(
        ['역사 이야기 정보', '과학기술 지식', '뉴스 분석 해설'].map(q =>
          fetchJson(`https://www.googleapis.com/youtube/v3/search?part=snippet&type=channel&q=${encodeURIComponent(q)}&regionCode=${region}&order=viewCount&relevanceLanguage=ko&maxResults=10&key=${key}`)
        )
      );
      const seen = new Set(bChannelIds);
      dRes.forEach(d => {
        (d.items||[]).forEach(item => {
          const chId = item.id?.channelId;
          if (chId && !seen.has(chId)) { seen.add(chId); dChannelIds.push(chId); }
        });
      });
      localStorage.setItem(CH_D_CACHE_KEY, JSON.stringify({ slot: dSlot, data: dChannelIds }));
    }

    // ── 채널 메타 조회 ──
    const allChIds = [...new Set([...bChannelIds, ...dChannelIds])];
    if (!allChIds.length) {
      state.channelData = { channels: [], updatedAt: Date.now() };
      return;
    }

    const chunk = (arr,n) => Array.from({length:Math.ceil(arr.length/n)},(_,i)=>arr.slice(i*n,i*n+n));
    const metaRes = await Promise.all(
      chunk(allChIds, 50).map(ids =>
        fetchJson(`https://www.googleapis.com/youtube/v3/channels?part=snippet,statistics,contentDetails&id=${ids.join(',')}&key=${key}`)
      )
    );

    let channels = [];
    metaRes.forEach(d => {
      (d.items||[]).forEach(ch => {
        const subs = parseInt(ch.statistics?.subscriberCount || 0);
        if (subs < 1000) return;
        channels.push({
          channelId: ch.id,
          title: ch.snippet?.title || '',
          thumbnail: ch.snippet?.thumbnails?.default?.url || '',
          subs, videoCount: parseInt(ch.statistics?.videoCount || 0),
          uploadsPlaylistId: ch.contentDetails?.relatedPlaylists?.uploads || '',
          source: bChannelIds.includes(ch.id) ? 'B' : 'D',
          top3: [], hasRecentVideos: false, aiDiff: null,
        });
      });
    });
    channels = channels.slice(0, 20); // 쿼터 절감: 최대 20채널

    // ── 채널별 최근 90일 영상 조회 ──
    const cutoff = new Date(Date.now() - 90*86400000).toISOString();
    const plRes = await Promise.all(
      channels.map(ch =>
        ch.uploadsPlaylistId
          ? fetchJson(`https://www.googleapis.com/youtube/v3/playlistItems?part=snippet&playlistId=${ch.uploadsPlaylistId}&maxResults=15&key=${key}`)
          : Promise.resolve({ items: [] })
      )
    );

    // 전체 비디오ID 수집
    const allVids = [];
    plRes.forEach((res, chIdx) => {
      (res.items||[]).forEach(item => {
        const vId = item.snippet?.resourceId?.videoId;
        const pub  = item.snippet?.publishedAt || '';
        if (vId && pub >= cutoff) allVids.push({ vId, chIdx, pub });
      });
    });

    if (allVids.length) {
      const vIdUniq = [...new Set(allVids.map(v => v.vId))];
      const vRes = await Promise.all(
        chunk(vIdUniq, 50).map(ids =>
          fetchJson(`https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet&id=${ids.join(',')}&key=${key}`)
        )
      );
      const vMap = {};
      vRes.forEach(d => { (d.items||[]).forEach(v => { vMap[v.id] = v; }); });

      channels.forEach((ch, chIdx) => {
        const vidObjs = [];
        allVids.filter(v => v.chIdx === chIdx).forEach(({ vId }) => {
          const v = vMap[vId];
          if (!v) return;
          const views = parseInt(v.statistics?.viewCount || 0);
          if (views < 5000) return;
          const publishedAt = v.snippet?.publishedAt || '';
          const days = (Date.now() - new Date(publishedAt).getTime()) / 86400000;
          const weight = days <= 7 ? 2.0 : days <= 30 ? 1.5 : 1.0;
          const baseEff = ch.subs > 0 ? views / ch.subs : 0;
          vidObjs.push({
            videoId: vId,
            title: v.snippet?.title || '',
            thumbnail: v.snippet?.thumbnails?.medium?.url || v.snippet?.thumbnails?.default?.url || '',
            publishedAt, views,
            catId: v.snippet?.categoryId || '',
            baseEff, adjEff: baseEff * weight,
          });
        });
        vidObjs.sort((a,b) => b.adjEff - a.adjEff);
        ch.top3 = vidObjs.slice(0, 3);
        ch.hasRecentVideos = ch.top3.length > 0;
        if (ch.hasRecentVideos) ch.aiDiff = calcAiDifficulty(ch.top3);
      });
    }

    // 최근 영상 있는 채널 우선
    const active   = channels.filter(ch => ch.hasRecentVideos);
    const inactive = channels.filter(ch => !ch.hasRecentVideos);
    state.channelData = { channels: [...active, ...inactive], updatedAt: Date.now() };

  } catch(err) {
    console.error('Channel panel error:', err);
    if (!state.channelData) state.channelData = { channels: [], updatedAt: Date.now() };
  } finally {
    state.channelLoading = false;
    const col3Final = document.getElementById('col3Panel');
    if (col3Final) renderChannelCol(col3Final);
  }
}

