/* ── Channel Panel ── */
.ch-refresh-btn {
  background: none; border: none; color: #555; cursor: pointer;
  font-size: 14px; padding: 2px 6px; border-radius: 3px; margin-left: auto;
}
.ch-refresh-btn:hover { color: #aaa; background: #222; }
.ch-last-update { font-size: 10px; color: #444; }

.channel-card { padding: 10px 0; border-bottom: 1px solid #1e1e1e; }
.channel-card:last-child { border-bottom: none; }
.ch-header { display: flex; gap: 8px; margin-bottom: 8px; }
.ch-thumb {
  width: 42px; height: 42px; border-radius: 50%; object-fit: cover;
  background: #222; flex-shrink: 0;
}
.ch-info { flex: 1; min-width: 0; }
.ch-name { font-size: 12px; font-weight: 700; margin-bottom: 2px; }
.ch-name a { color: #e8e8e8; text-decoration: none; }
.ch-name a:hover { color: #ff6666; }
.ch-meta { font-size: 10px; color: #666; margin-bottom: 3px; }
.ch-tags { display: flex; gap: 4px; flex-wrap: wrap; align-items: center; }
.ch-cat-tag {
  font-size: 10px; padding: 1px 5px; border-radius: 8px;
  border: 1px solid #2a2a2a; color: #777; background: #1a1a1a;
}
.ai-diff-badge { font-size: 10px; padding: 1px 6px; border-radius: 8px; font-weight: 600; }
.diff-1 { background: #1a2e1a; border: 1px solid #2a6a2a; color: #6dcc6d; }
.diff-2 { background: #2e2a1a; border: 1px solid #6a5a2a; color: #ccbb6d; }
.diff-3 { background: #2e2218; border: 1px solid #6a4a2a; color: #cc8844; }
.ch-source-tag {
  font-size: 9px; padding: 1px 5px; border-radius: 8px;
  background: #1a1a2e; border: 1px solid #2a2a5a; color: #6666bb;
}
.ch-source-tag.d-src { background: #1e1a2e; border-color: #3a2a5a; color: #8866bb; }

.ch-videos { }
.ch-video-item {
  display: flex; gap: 6px; align-items: flex-start;
  padding: 5px 0; border-top: 1px solid #181818;
}
.ch-rank {
  font-size: 11px; font-weight: 700; color: #555;
  width: 14px; flex-shrink: 0; padding-top: 2px; text-align: center;
}
.ch-video-thumb {
  width: 80px; height: 45px; object-fit: cover; border-radius: 3px;
  background: #222; flex-shrink: 0;
}
.ch-video-info { flex: 1; min-width: 0; }
.ch-video-title {
  font-size: 11px; line-height: 1.3; margin-bottom: 3px;
  display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden;
}
.ch-video-title a { color: #ccc; text-decoration: none; }
.ch-video-title a:hover { color: #ff6666; }
.ch-video-stats { display: flex; gap: 5px; align-items: center; flex-wrap: wrap; }
.ch-recency { font-size: 10px; color: #555; }
.ch-recency.fresh  { color: #4a9a4a; }
.ch-recency.recent { color: #7a7a4a; }
.ch-inactive-note {
  font-size: 10px; color: #444; padding: 6px 0;
  border-top: 1px solid #181818; text-align: center;
}
.ch-no-data { text-align: center; padding: 30px 10px; color: #444; font-size: 11px; }

