.topic-sort-bar {
  display: flex; gap: 3px; padding: 6px 10px 5px;
  border-bottom: 1px solid #1e1e1e;
}
.topic-sort-btn {
  background: #222; border: 1px solid #333; color: #888;
  padding: 2px 8px; border-radius: 3px; cursor: pointer; font-size: 11px;
}
.topic-sort-btn:hover { color: #ccc; background: #2a2a2a; }
.topic-sort-btn.active { background: #ff0000; border-color: #ff0000; color: white; font-weight: 700; }

.topic-cluster-card { padding: 10px 10px 8px; border-bottom: 1px solid #1e1e1e; }
.topic-cluster-card:last-child { border-bottom: none; }

.cluster-header { display: flex; align-items: center; gap: 6px; margin-bottom: 4px; }
.cluster-icon { font-size: 14px; }
.cluster-name { font-size: 12px; font-weight: 700; color: #ddd; flex: 1; }
.cluster-count {
  font-size: 10px; color: #666;
